/** pointChkScheduleMapper.updateJejuPointMst */ UPDATE MSP_PARTNER_POINT_MST A SET PAY_RESULT = #{payResult} , RESULT_DTL_CD = #{responseCode} , PAY_DTTM = SYSDATE , RVISN_ID = 'POINT' , RVISN_DTTM = SYSDATE
, PAY_POINT = REQ_POINT
WHERE A.SEND_FLAG = 'R' AND A.FULL_PAY_YN = 'Y' AND A.PAY_RESULT <> 'S' AND A.PARTNER_ID = #{partnerId} AND A.SVC_CNTR_NO IN (SELECT D.SVC_CNTR_NO FROM MSP_PARTNER_POINT_MST B, MSP_JUO_CUS_INFO C, MSP_JUO_SUB_INFO D WHERE C.CUSTOMER_ID = D.CUSTOMER_ID AND B.SVC_CNTR_NO = D.SVC_CNTR_NO AND B.PARTNER_ID = #{partnerId} AND C.SELF_CSTMR_CI = #{memberCi})

/** pointChkScheduleMapper.updatePartnerJejuair */
UPDATE 
		MSP_PARTNER_JEJUAIR_01
SET 
		RESULT_DTL_CD = #{responseCode}
		, RVISN_ID = 'POINT'
		, RVISN_DTTM = SYSDATE
WHERE BILL_YM = #{billYm}
AND   MEMBER_CI = #{memberCi}

/** pointChkScheduleMapper.updateGiftiPointMst */
UPDATE 
		MSP_PARTNER_POINT_MST A
SET 
		PAY_RESULT = #{payResult}
		, RESULT_DTL_CD = #{responseCode}
		, PAY_DTTM = SYSDATE
		, RVISN_ID = 'POINT'
		, RVISN_DTTM = SYSDATE

			, PAY_POINT = REQ_POINT

WHERE A.SEND_FLAG = 'R'
AND   A.FULL_PAY_YN = 'Y'
AND   A.PAY_RESULT <> 'S'
AND   A.PARTNER_ID = #{partnerId}
AND   A.CONTRACT_NUM = #{contractNum}

/** pointChkScheduleMapper.updatePartnerGifti */
UPDATE 
		MSP_PARTNER_GIFTI_01
SET 
		RESULT_DTL_CD = #{responseCode}
		, RVISN_ID = 'POINT'
		, RVISN_DTTM = SYSDATE
WHERE  LINK_YM = #{linkYm}
AND    USG_YM = #{usgYm}
AND    CONTRACT_NUM = #{contractNum}
AND    CTN = #{ctn}

/** pointChkScheduleMapper.updateTmoneyPointMst */
UPDATE 
		MSP_PARTNER_POINT_MST A
SET 
		PAY_RESULT = #{payResult}
		, RESULT_DTL_CD = #{responseCode}
		, PAY_DTTM = SYSDATE
		, RVISN_ID = 'POINT'
		, RVISN_DTTM = SYSDATE

			, PAY_POINT = REQ_POINT

WHERE A.SEND_FLAG = 'R'
AND   A.FULL_PAY_YN = 'Y'
AND   A.PAY_RESULT <> 'S'
AND   A.PARTNER_ID = #{partnerId}
AND   A.PARTNER_ID = #{partnerId}
AND   A.CONTRACT_NUM = #{contractNum}
AND   A.BILL_YM = #{billYm}

/** pointChkScheduleMapper.updatePartnerTmoney */
UPDATE 
		MSP_PARTNER_TMONEY_01
SET 
		RESULT_DTL_CD = #{responseCode}
		, RVISN_ID = 'POINT'
		, RVISN_DTTM = SYSDATE
WHERE LINK_YM = #{linkYm}
AND   UICC = #{uicc}
AND   BILL_YM = #{billYm}

