UPDATE	/* pointChkScheduleMapper.updatePointFileUp */
		MSP_PARTNER_POINT_FILE
SET
		SEND_FLAG = #{sendFlag}
		, REGST_ID = 'POINT'
		, REGST_DTTM = SYSDATE
WHERE 	PARTNER_ID = #{partnerId}
AND     FILE_NM = #{fileNm}

UPDATE	/* pointChkScheduleMapper.updatePointFileDown */
		MSP_PARTNER_POINT_FILE
SET
		SEND_RESULT = #{sendResult}
		, RVISN_ID = 'POINT'
		, RVISN_DTTM = SYSDATE
WHERE 	PARTNER_ID = #{partnerId}
AND     FILE_NM = #{fileNm}

mapper.select:
/* pointChkScheduleMapper.getPointFileUpList */ SELECT PARTNER_ID , FILE_NM , LOCAL_UP_DIR , HOST_UP_DIR FROM MSP_PARTNER_POINT_FILE WHERE SEND_FLAG <> 'S'
AND PARTNER_ID = #{partnerId}
AND FILE_NM = #{fileNm}

/* pointChkScheduleMapper.getPointFileDownList */ SELECT PARTNER_ID , FILE_NM , LOCAL_DOWN_DIR , HOST_DOWN_DIR FROM MSP_PARTNER_POINT_FILE WHERE SEND_FLAG = 'S' AND SEND_RESULT IN ('R', 'F')
AND PARTNER_ID = #{partnerId}
AND FILE_NM = #{fileNm}

/* pointChkScheduleMapper.getPointFileReadList */ SELECT PARTNER_ID , FILE_NM , LOCAL_DOWN_DIR FROM MSP_PARTNER_POINT_FILE WHERE SEND_FLAG = 'S' AND SEND_RESULT = 'D'
AND PARTNER_ID = #{partnerId}
AND FILE_NM = #{fileNm}
